def calculate_risk_score(sex, adls, chf, cancer, creatinine, albumin):
    """
    Calculate the risk score based on the given parameters.

    Parameters:
    sex (str): 'male' or 'female'
    adls (int): number of dependent Activities of Daily Living (0-5)
    chf (bool): whether the patient has congestive heart failure
    cancer (str): 'none', 'solitary', or 'metastatic'
    creatinine (float): creatinine level in mg/dL
    albumin (float): albumin level in g/dL

    Returns:
    int: the calculated risk score
    """
    score = 0
    if sex == 'male':
        score += 1
    if adls >= 1 and adls <= 4:
        score += 2
    elif adls == 5:
        score += 5
    if chf:
        score += 2
    if cancer == 'solitary':
        score += 3
    elif cancer == 'metastatic':
        score += 8
    if creatinine > 3.0:
        score += 2
    if albumin >= 3.0 and albumin <= 3.4:
        score += 1
    elif albumin < 3.0:
        score += 2
    return score

