def compute_essen_ich_score(age, nihss_consciousness, nihss_total):
    """
    Compute the Essen ICH score based on age, NIH-SS level of consciousness, and NIH-SS total score.

    Parameters:
    age (int): patient's age
    nihss_consciousness (str): patient's NIH-SS level of consciousness (alert, drowsy, stuporose, comatose)
    nihss_total (int): patient's NIH-SS total score

    Returns:
    int: Essen ICH score
    """
    # Age subscore
    if age < 60:
        age_score = 0
    elif 60 <= age < 70:
        age_score = 1
    elif 70 <= age < 80:
        age_score = 2
    else:
        age_score = 3

    # NIH-SS level of consciousness subscore
    if nihss_consciousness == 'alert':
        consciousness_score = 0
    elif nihss_consciousness == 'drowsy':
        consciousness_score = 1
    elif nihss_consciousness == 'stuporose':
        consciousness_score = 2
    else:
        consciousness_score = 3

    # NIH-SS total score subscore
    if nihss_total <= 5:
        total_score = 0
    elif 6 <= nihss_total <= 10:
        total_score = 1
    elif 11 <= nihss_total <= 15:
        total_score = 2
    elif 16 <= nihss_total <= 20:
        total_score = 3
    else:
        total_score = 4

    # Essen ICH score
    essen_ich_score = age_score + consciousness_score + total_score

    return essen_ich_score

