def calculate_GAP_score(gender, age, fvc, dlco):
    """
    Calculate GAP score for IPF prognosis.

    Parameters:
    gender (str): 'male' or 'female'
    age (int): age in years
    fvc (float): Forced Vital Capacity as a percentage
    dlco (float): Diffusion Capacity of the Lung for Carbon Monoxide as a percentage

    Returns:
    int: GAP score
    """
    # Assign points based on gender
    if gender.lower() == 'male':
        gender_points = 1
    else:
        gender_points = 0

    # Assign points based on age
    if age < 60:
        age_points = 0
    elif 60 <= age < 65:
        age_points = 1
    elif 65 <= age < 70:
        age_points = 2
    else:
        age_points = 3

    # Assign points based on FVC
    if fvc > 80:
        fvc_points = 0
    elif 80 >= fvc > 50:
        fvc_points = 1
    else:
        fvc_points = 2

    # Assign points based on DLCO
    if dlco > 55:
        dlco_points = 0
    elif 55 >= dlco > 35:
        dlco_points = 1
    else:
        dlco_points = 2

    # Calculate GAP score
    GAP_score = gender_points + age_points + fvc_points + dlco_points

    return GAP_score

