def compute_risk_score(age, previous_mi, creatinine_clearance, abi, crp, medication):
    """
    Compute the COPART risk score for hospitalised severe PAD.

    Parameters:
    age (int): Age of the patient
    previous_mi (bool): Whether the patient had a previous myocardial infarction
    creatinine_clearance (float): Creatinine clearance of the patient
    abi (float): Ankle-brachial index of the patient
    crp (float): C-reactive protein level of the patient
    medication (bool): Whether the patient is on statins, anti-platelet agents and renin-angiotin system inhibitors

    Returns:
    float: The computed risk score
    """
    score = 0
    if 75 <= age < 85:
        score += 2
    elif age >= 85:
        score += 3
    if previous_mi:
        score += 1
    if creatinine_clearance <= 30:
        score += 1.5
    elif 30 < creatinine_clearance <= 59:
        score += 1
    if abi < 0.3:
        score += 2
    elif 0.3 <= abi <= 0.49 or abi > 1.3:
        score += 1.5
    if crp >= 70:
        score += 2
    if medication:
        score -= 1.5
    return score

