def calculate_edema_score(basal_cistern_effacement, glucose, tpa_or_thrombectomy, midline_shift, previous_stroke):
    """
    Calculate the EDEMA score based on the given parameters.

    Parameters:
    basal_cistern_effacement (bool): True if basal cistern effacement is present, False otherwise.
    glucose (int): Glucose level.
    tpa_or_thrombectomy (bool): True if tPA or thrombectomy was performed, False otherwise.
    midline_shift (float): The degree of midline shift.
    previous_stroke (bool): True if the patient has had a previous stroke, False otherwise.

    Returns:
    int: The calculated EDEMA score.
    """
    score = 0
    if basal_cistern_effacement:
        score += 3
    if glucose >= 150:
        score += 2
    if not tpa_or_thrombectomy:
        score += 1
    if 0 < midline_shift <= 3:
        score += 1
    elif 3 < midline_shift <= 6:
        score += 2
    elif 6 < midline_shift <= 9:
        score += 4
    elif midline_shift > 9:
        score += 7
    if not previous_stroke:
        score += 1
    return score

