def compute_risk_score(age, gender, systolic_hypertension, overweight, excessive_drinking, coronary_artery_disease, current_smoking, moderate_non_hdl_cholesterol, arrhythmia, cardiac_murmur):
    """
    Compute the risk score for atrial fibrillation based on the given parameters.

    Parameters:
    age (int): Age of the patient in years.
    gender (str): Gender of the patient. Can be 'male' or 'female'.
    systolic_hypertension (bool): Whether the patient has systolic hypertension.
    overweight (bool): Whether the patient is overweight.
    excessive_drinking (bool): Whether the patient drinks excessively.
    coronary_artery_disease (bool): Whether the patient has coronary artery disease.
    current_smoking (bool): Whether the patient is a current smoker.
    moderate_non_hdl_cholesterol (bool): Whether the patient has moderate non-high-density lipoprotein-cholesterol.
    arrhythmia (bool): Whether the patient has arrhythmia.
    cardiac_murmur (bool): Whether the patient has cardiac murmur.

    Returns:
    int: The computed risk score.
    """
    score = 0

    # Age and gender
    if gender == 'male':
        if age >= 30 and age < 50:
            score += 0
        elif age >= 50 and age < 60:
            score += 3
        elif age >= 60 and age < 70:
            score += 7
        elif age >= 70:
            score += 9
    else:  # female
        if age >= 30 and age < 50:
            score += -5
        elif age >= 50 and age < 60:
            score += 0
        elif age >= 60 and age < 70:
            score += 5
        elif age >= 70:
            score += 9

    # Other risk factors
    if systolic_hypertension:
        score += 2
    if overweight:
        score += 2
    if excessive_drinking:
        score += 2
    if coronary_artery_disease:
        score += 2
    if current_smoking:
        score += 1
    if moderate_non_hdl_cholesterol:
        score += -1
    if arrhythmia:
        score += 4
    if cardiac_murmur:
        if age >= 30 and age < 50:
            score += 8
        elif age >= 50 and age < 60:
            score += 6
        elif age >= 60:
            score += 2

    return score

