    int: The BALLAR score.
    """
    score = 0

    # Lactate
    if lactate <= 1.9:
        score += 0
    elif 2 <= lactate < 5:
        score += 1
    else:
        score += 4

    # Creatinine Clearance
    if creatinine_clearance <= 29.9:
        score += 6
    elif 30 <= creatinine_clearance < 60:
        score += 4
    elif 60 <= creatinine_clearance < 90:
        score += 1
    else:
        score += 0

    # Serum Albumin
    if serum_albumin < 25:
        score += 6
    elif 25 <= serum_albumin < 35:
        score += 3
    else:
        score += 0

    # Base Excess
    if base_excess < -2:
        score += 2
    else:
        score += 0

    return score

